```julia
function IntegralProblem(f, x::AbstractVector{<:Number}, args...; kwargs...)
    IntegralProblem{isinplace(f, 3)}(f, x, args...; kwargs...)
end
function IntegralProblem(y::AbstractArray, x::AbstractVector{<:Number}, args...; dim::Int=1, kwargs...)
    IntegralProblem{false}(y, x, args...; dim=Val(dim), kwargs...)
end
```

The first for integrating a callable `f` over some set of sample points `x`, and the second for integrating an `Array` `y` over some dimension `dim.` I chose to put `x` second in both of these (contrary to what is usual in many packages/languages), because this way it is consistent with the `IntegralProblem(f, lb, ub)` ordering. Let me know if you agree.","reactions":{"url":"https://api.github.com/repos/SciML/SciMLBase.jl/issues/comments/1717121409/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"performed_via_github_app":null}}

